    fn eq(&self, other: &Self) -> bool {
        match (self, other) {
            (Self::File(l0), Self::File(r0)) => l0.as_ref() as *const _ == r0.as_ref(),
            (Self::Shm(l0), Self::Shm(r0)) => l0.get_id() == r0.get_id(),
