                user_stack_bottom.into()..user_stack_top.into(),
                UserVmAreaType::Stack,
                MapPerm::R | MapPerm::W | MapPerm::U,
            ),
            None,
        );

        Ok((
            ret,
            user_stack_top,
            entry,
            auxv,
        ))
    }

