            file.file_close().expect("failed to close");
            fsize
        } else {
            0
        };

        Self {
            inner: InodeInner::new(Some(super_block.clone()), mode, size as usize),
            file: SpinNoIrqLock::new(file),
            cache: Arc::new(PageCache::new()),
        }
